import java.util.Arrays;

public int maxIceCream(int[] costs, int coins) {
    Arrays.sort(costs);
    int count = 0;
    for (int cost : costs) {
        if (coins >= cost) {
            coins -= cost;
            count++;
        } else {
            break;
        }
    }
    return count;
}
```

